import java.util.*;

public class KMPSearch {

    public int[] buildLPS(String pattern) {
        int m = pattern.length();
        int[] lps = new int[m];
        int len = 0, i = 1;
        while (i < m) {
            if (pattern.charAt(i) == pattern.charAt(len)) {
                lps[i++] = ++len;
            } else {
                if (len != 0) len = lps[len - 1];
                else lps[i++] = 0;
            }
        }
        return lps;
    }

    public List<Integer> search(String text, String pattern) {
        List<Integer> positions = new ArrayList<>();
        int n = text.length(), m = pattern.length();
        int[] lps = buildLPS(pattern);
        int i = 0, j = 0; // i=text index, j=pattern index
        while (i < n) {
            if (text.charAt(i) == pattern.charAt(j)) {
                i++; j++;
            }
            if (j == m) {
                positions.add(i - j);
                j = lps[j - 1]; // slide using LPS
            } else if (i < n && text.charAt(i) != pattern.charAt(j)) {
                // TODO: if j != 0, use LPS to set j = lps[j-1]; else increment i
            }
        }
        return positions;
    }

    public static void main(String[] args) {
        KMPSearch kmp = new KMPSearch();
        System.out.println(kmp.search("AABAACAADAABAABA", "AABA"));
        System.out.println(kmp.search("ABABABCABABABCABABABC", "ABABAB"));
        System.out.println(Arrays.toString(kmp.buildLPS("AAACAAAA")));
    }
}

import java.util.*;

public class AnagramSearch {

    public List<Integer> findAnagrams(String text, String pattern) {
        List<Integer> result = new ArrayList<>();
        int n = text.length(), m = pattern.length();
        if (n < m) return result;

        int[] patCount  = new int[26];
        int[] winCount  = new int[26];

        // Build frequency for pattern and first window
        for (int i = 0; i < m; i++) {
            patCount[pattern.charAt(i) - 'a']++;
            winCount[text.charAt(i)   - 'a']++;
        }
        if (Arrays.equals(patCount, winCount)) result.add(0);

        // Slide window
        for (int i = m; i < n; i++) {
            // TODO: Add text.charAt(i) to window
            // TODO: Remove text.charAt(i - m) from window
            // TODO: If patCount equals winCount, add (i - m + 1) to result
        }
        return result;
    }

    public static void main(String[] args) {
        AnagramSearch as = new AnagramSearch();
        System.out.println(as.findAnagrams("cbaebabacd", "abc"));
        System.out.println(as.findAnagrams("abab", "ab"));
        System.out.println(as.findAnagrams("aaa", "b"));
    }
}
